args.sparql:
SELECT DISTINCT ?team ?stadium WHERE {
  ?league rdfs:label ?label .
  FILTER (LANG(?label) = 'en')
  FILTER (CONTAINS(LCASE(?label), 'hong kong third division'))
  ?league wdt:P31 wd:Q3676783 .
  ?league wdt:P17 wd:Q9128 .

  ?team wdt:P31 wd:Q7943827 .
  ?team p:P725 ?statement .
  ?statement ps:P725 ?league ;
            pq:P585 ?seasonDate ;
            pq:P1363 3 .

  ?team wdt:P189 ?stadium .
} LIMIT 1

SELECT DISTINCT ?team ?stadium WHERE {
  wd:Q6213968 wdt:P31 wd:Q3676783 .
  ?team wdt:P31 wd:Q7943827 .
  ?team p:P527 ?statement .
  ?statement ps:P527 wd:Q6213968 ;
            pq:P585 ?seasonDate ;
            pq:P1363 ?position .
  FILTER (?position = 3)
  FILTER (YEAR(?seasonDate) = 2012)
  ?team wdt:P189 ?stadium .
} LIMIT 1
